func (m *WebhookAuthModel) toAPI() (api.ConnectorWebhookAuth, diag.Diagnostics) {
	var diags diag.Diagnostics
	var result api.ConnectorWebhookAuth

	if m.Bearer != nil {
		inner, d := m.Bearer.toAPI()
		diags.Append(d...)
		if diags.HasError() {
			return result, diags
		}
		wrapper := api.ConnectorWebhookAuth0{Bearer: inner}
		if err := result.FromConnectorWebhookAuth0(wrapper); err != nil {
			diags.AddError("Failed to set variant", err.Error())
			return result, diags
		}
	} else if m.Basic != nil {
		inner, d := m.Basic.toAPI()
		diags.Append(d...)
		if diags.HasError() {
			return result, diags
		}
		wrapper := api.ConnectorWebhookAuth1{Basic: inner}
		if err := result.FromConnectorWebhookAuth1(wrapper); err != nil {
			diags.AddError("Failed to set variant", err.Error())
			return result, diags
		}
	} else if m.Header != nil {
		inner, d := m.Header.toAPI()
		diags.Append(d...)
		if diags.HasError() {
			return result, diags
		}
		wrapper := api.ConnectorWebhookAuth2{Header: inner}
		if err := result.FromConnectorWebhookAuth2(wrapper); err != nil {
			diags.AddError("Failed to set variant", err.Error())
			return result, diags
		}
	}
	return result, diags
}

func (m *WebhookAuthModel) mergeFromAPI(a api.ConnectorWebhookAuth, state *WebhookAuthModel) {
	keysJSON, _ := json.Marshal(a)
	var keys map[string]json.RawMessage
	_ = json.Unmarshal(keysJSON, &keys)

	if _, ok := keys["bearer"]; ok {
		if m.Bearer == nil {
			m.Bearer = &WebhookBearerAuthModel{}
		}
		if state != nil && state.Bearer != nil {
			m.Bearer.Token = state.Bearer.Token
		}
	} else if _, ok := keys["basic"]; ok {
		inner, _ := a.AsConnectorWebhookAuth1()
		if m.Basic == nil {
			m.Basic = &WebhookBasicAuthModel{}
		}
		var st *WebhookBasicAuthModel
		if state != nil {
			st = state.Basic
		}
		m.Basic.mergeFromAPI(inner.Basic, st)
	} else if _, ok := keys["header"]; ok {
		inner, _ := a.AsConnectorWebhookAuth2()
		if m.Header == nil {
			m.Header = &WebhookHeaderAuthModel{}
		}
		var st *WebhookHeaderAuthModel
		if state != nil {
			st = state.Header
		}
		m.Header.mergeFromAPI(inner.Header, st)
	}
}

